-- 015_add_tempus_praeteritum.sql
-- Fuegt der Baustein-Bibliothek die fehlende Vergangenheitsform (Praeteritum)
-- hinzu: bisher gab es je Skill/Bewertung nur die Praesens-Fassung, die auch
-- fuer Schlusszeugnisse verwendet wurde (falsche Zeitform bei rueckblickenden
-- Zeugnissen). Ab jetzt waehlt die Engine (siehe findPhrase() in
-- lib/phrases/engine.ts) je nach Zeugnistyp den passenden Pool:
--   Zwischenzeugnis -> tempus='praesens' (unveraendert)
--   alle anderen Typen (Schluss/Wechsel/...) -> tempus='praeteritum'
-- Fehlt fuer eine Kombination ausnahmsweise eine Praeteritum-Variante, faellt
-- die Engine automatisch auf die Praesens-Fassung zurueck (kein Ausfall).
--
-- Additiv und idempotent: bestehende Praesens-Zeilen werden NICHT veraendert
-- oder geloescht (Konsistenz mit bereits finalisierten Zeugnissen bleibt
-- gewahrt). Manuell im Supabase-SQL-Editor (Projekt "zeugnix") auszufuehren.
-- 427 neue Zeilen (Vergangenheitsform je bestehende Praesens-Variante).

begin;

-- 1) Enum-Wert-Typ + Spalte idempotent anlegen (Fresh-Installs haben das
--    bereits aus 001_initial_schema.sql; hier fuer die bereits laufende
--    Prod-Datenbank nachgezogen).
do $$ begin
  create type tempus_value as enum ('praesens', 'praeteritum');
exception when duplicate_object then null; end $$;

alter table public.phrase_blocks
  add column if not exists tempus tempus_value not null default 'praesens';

-- 2) Praeteritum-Fassung der 427 bestehenden Beurteilungs-Bausteine einfuegen.
--    (Einleitung/Schluss aus 002_seed_phrases.sql sind bewusst nicht
--    betroffen -- sie bleiben tempus='praesens' per Spalten-Default.)

commit;
