('vorbild', 'fuehrung', 'fuehrungskraft', 'd', 'ungenuegend', 1, 'praeteritum', '{vorname} {nachname} schätzten wir als Führungspersönlichkeit, {{dessen|deren|dessen/deren}} Führungsleistung auf Glaubwürdigkeit basierte.'),
('vorbild', 'fuehrung', 'fuehrungskraft', 'd', 'ungenuegend', 2, 'praeteritum', '{vorname} {nachname} erlebten wir als {{Vorgesetzten|Vorgesetzte|Vorgesetzten/Vorgesetzte}}, {{der|die|der/die}} jeweils mit {{seinem|ihrem|seinem/ihrem}} Team solide Leistungen erbrachte.'),
('vorbild', 'fuehrung', 'fuehrungskraft', 'd', 'genuegend', 1, 'praeteritum', '{vorname} {nachname} schätzten wir als zuverlässige Führungspersönlichkeit, {{dessen|deren|dessen/deren}} Führungsleistung auf Glaubwürdigkeit und Integrität basierte.'),
('vorbild', 'fuehrung', 'fuehrungskraft', 'd', 'genuegend', 2, 'praeteritum', '{vorname} {nachname} erlebten wir als motivierte Führungskraft, die verantwortungsvoll handelte. Entscheidungen traf {{er|sie|er/sie}} durchdacht, kommunizierte diese klar und nachvollziehbar.'),
('vorbild', 'fuehrung', 'fuehrungskraft', 'd', 'gut', 1, 'praeteritum', '{vorname} {nachname} schätzten wir als engagierte Führungspersönlichkeit, {{dessen|deren|dessen/deren}} vorbildliche Führungsleistung auf Glaubwürdigkeit und Integrität basierte.'),
('vorbild', 'fuehrung', 'fuehrungskraft', 'd', 'gut', 2, 'praeteritum', '{vorname} {nachname} schätzten wir als engagierte und integre Führungskraft, die vorausschauend, ziel- und umsetzungsorientiert sowie im Sinne unserer Wertekultur handelte. {{Er|Sie|Er/Sie}} verfügte über Selbstdisziplin und übernahm stets Verantwortung. Entscheidungen traf {{er|sie|er/sie}} gut durchdacht, kommunizierte diese zeitgerecht, klar und nachvollziehbar. Zudem überzeugte {{er|sie|er/sie}} durch {{seinen|ihren|seinen/ihren}} kooperativen Führungsstil.'),
('vorbild', 'fuehrung', 'fuehrungskraft', 'd', 'sehr_gut', 1, 'praeteritum', '{vorname} {nachname} schätzten wir als sehr engagierte Führungspersönlichkeit, {{dessen|deren|dessen/deren}} vorbildliche und beeindruckende Führungsleistung auf Glaubwürdigkeit und Integrität basierte.'),
('vorbild', 'fuehrung', 'fuehrungskraft', 'd', 'sehr_gut', 2, 'praeteritum', '{vorname} {nachname} schätzten wir als sehr engagierte und integre Führungskraft, die vorausschauend, ziel- und umsetzungsorientiert sowie im Sinne unserer Wertekultur dachte und agierte. {{Er|Sie|Er/Sie}} verfügte über einen hohen Grad an Selbstdisziplin und übernahm stets Verantwortung. Entscheidungen traf {{er|sie|er/sie}} bestens durchdacht und kommunizierte diese zeitgerecht, klar und nachvollziehbar. Zudem überzeugte {{er|sie|er/sie}} jederzeit durch {{sein|ihr|sein/ihr}} vorbildliches Engagement sowie durch {{seinen|ihren|seinen/ihren}} kooperativen, sach- und personenbezogenen Führungsstil.'),
('offenheit_vertrauen', 'fuehrung', 'fuehrungskraft', 'd', 'ungenuegend', 1, 'praeteritum', 'Durch {{sein|ihr|sein/ihr}} Interesse gegenüber den Anliegen {{seiner|ihrer|seiner/ihrer}} Mitarbeitenden schuf {{er|sie|er/sie}} ein angenehmes Arbeitsklima.'),
('offenheit_vertrauen', 'fuehrung', 'fuehrungskraft', 'd', 'ungenuegend', 2, 'praeteritum', 'Den Anliegen {{seiner|ihrer|seiner/ihrer}} Mitarbeitenden stand {vorname} {nachname} jeweils offen gegenüber.'),
('offenheit_vertrauen', 'fuehrung', 'fuehrungskraft', 'd', 'genuegend', 1, 'praeteritum', 'Durch {{sein|ihr|sein/ihr}} echtes Interesse gegenüber den Anliegen {{seiner|ihrer|seiner/ihrer}} Mitarbeitenden schuf {{er|sie|er/sie}} ein vertrauensvolles Arbeitsklima.'),
('offenheit_vertrauen', 'fuehrung', 'fuehrungskraft', 'd', 'genuegend', 2, 'praeteritum', 'Den Anliegen {{seiner|ihrer|seiner/ihrer}} Mitarbeitenden gegenüber war {vorname} {nachname} jeweils offen. Durch {{seine|ihre|seine/ihre}} wertschätzende Haltung schuf {{er|sie|er/sie}} ein förderliches Arbeitsklima.'),
('offenheit_vertrauen', 'fuehrung', 'fuehrungskraft', 'd', 'gut', 1, 'praeteritum', 'Durch {{seine|ihre|seine/ihre}} Offenheit und echtes Interesse gegenüber den Anliegen {{seiner|ihrer|seiner/ihrer}} Mitarbeitenden schuf {{er|sie|er/sie}} ein vertrauensvolles und produktives Arbeitsklima.'),
('offenheit_vertrauen', 'fuehrung', 'fuehrungskraft', 'd', 'gut', 2, 'praeteritum', 'Als Führungskraft verstand {vorname} {nachname} es, {{seine|ihre|seine/ihre}} Mitarbeitenden entsprechend einzubeziehen und zielorientiert zu fördern. Durch {{seine|ihre|seine/ihre}} wertschätzende Haltung schuf {{er|sie|er/sie}} eine vertrauensvolle Basis der Zusammenarbeit sowie ein produktives Arbeitsklima. Vorschläge {{seiner|ihrer|seiner/ihrer}} Mitarbeitenden liess {{er|sie|er/sie}} sinnvoll und angemessen in die Umsetzung {{seiner|ihrer|seiner/ihrer}} Ziele einfliessen.'),
('offenheit_vertrauen', 'fuehrung', 'fuehrungskraft', 'd', 'sehr_gut', 1, 'praeteritum', 'Durch Begeisterungsfähigkeit, Offenheit und echtes Interesse gegenüber den Anliegen {{seiner|ihrer|seiner/ihrer}} Mitarbeitenden schuf {{er|sie|er/sie}} ein vertrauensvolles und produktives Arbeitsklima.'),
('offenheit_vertrauen', 'fuehrung', 'fuehrungskraft', 'd', 'sehr_gut', 2, 'praeteritum', 'Als Führungskraft verstand {vorname} {nachname} es jederzeit bestens, alle Mitarbeitenden {{seines|ihres|seines/ihres}} Teams entsprechend ihrer Persönlichkeiten und Kompetenzen einzubeziehen und zielorientiert zu fördern. Durch {{seine|ihre|seine/ihre}} wertschätzende Haltung schuf {{er|sie|er/sie}} aktiv eine vertrauensvolle Basis der Zusammenarbeit sowie ein produktives Arbeitsklima. Vorschläge {{seiner|ihrer|seiner/ihrer}} Mitarbeitenden liess {{er|sie|er/sie}} sinnvoll und angemessen in die Umsetzung {{seiner|ihrer|seiner/ihrer}} Ziele einfliessen.'),
('verantwortung_uebertragen', 'fuehrung', 'fuehrungskraft', 'd', 'ungenuegend', 1, 'praeteritum', 'Wir möchten erwähnen, dass {{er|sie|er/sie}} als {{Vorgesetzter|Vorgesetzte|Vorgesetzter/Vorgesetzte}} Aufgaben in massvollem Umfang delegierte.'),
